-- ===================================================================
-- PATCH — expande o banco de perguntas de 30 para 120 (todas diferentes)
--
-- COMO USAR: cole este arquivo inteiro no SQL Editor do Supabase e
-- clique em "Run". Ele apaga as perguntas antigas e insere as 120 novas
-- (o que é seguro: a tabela `questions` não guarda nenhum resultado de
-- jogador — isso fica em `results`, que não é tocada por este patch).
-- ===================================================================

delete from questions;

